type Account struct {
	Balance int
}

var accounts = make(map[int]*Account)
var mu sync.Mutex

func processTransaction(accountID int, amount int) {
	mu.Lock()
	defer mu.Unlock()

	// Check if account exists
	if _, ok := accounts[accountID]; !ok {
		fmt.Println("Account does not exist")
		return
	}

	// Update balance
	accounts[accountID].Balance += amount

	// Print updated balance
	fmt.Printf("Updated balance for account %d: %d\n", accountID, accounts[accountID].Balance)
}

